class TokenBucket {
  private tokens: number;
  private lastRefill: number;
  constructor(
    private readonly capacity: number,   // max burst B
    private readonly refillPerSec: number // steady rate R
  ) {
    this.tokens = capacity;
    this.lastRefill = Date.now();
  }

  tryConsume(cost = 1): boolean {
    this.refill();
    if (this.tokens >= cost) {
      this.tokens -= cost;
      return true;
    }
    return false;
  }

  private refill(): void {
    const now = Date.now();
    const elapsedSec = (now - this.lastRefill) / 1000;
    // lazy refill: add tokens for time elapsed, capped at capacity
    this.tokens = Math.min(
      this.capacity,
      this.tokens + elapsedSec * this.refillPerSec
    );
    this.lastRefill = now;
  }
}

