import { createClient } from 'redis';
import { Request, Response, NextFunction } from 'express';

const redis = createClient();
const LIMIT = 100;          // burst capacity B
const REFILL_PER_SEC = 10;  // steady rate R

export async function rateLimit(req: Request, res: Response, next: NextFunction) {
  const key = `rl:tb:${req.header('x-api-key') ?? req.ip}`;
  const now = Date.now();

  const [allowed, remaining, retryAfter] = (await redis.eval(
    TOKEN_BUCKET_LUA,
    { keys: [key], arguments: [String(now), String(LIMIT), String(REFILL_PER_SEC)] }
  )) as [number, number, number];

  res.setHeader('RateLimit-Limit', LIMIT);
  res.setHeader('RateLimit-Remaining', Math.max(0, remaining));

  if (allowed === 1) return next();

  res.setHeader('Retry-After', retryAfter);
  res.setHeader('RateLimit-Reset', retryAfter);
  return res.status(429).json({ error: 'rate_limited', message: `Retry after ${retryAfter}s` });
}

async function callWithBackoff(fn: () => Promise<Response>, maxRetries = 5) {
  for (let attempt = 0; attempt <= maxRetries; attempt++) {
    const res = await fn();
    if (res.status !== 429) return res;
    // honor Retry-After if present, else exponential backoff with jitter
    const ra = res.headers.get('Retry-After');
    const waitMs = ra
      ? Number(ra) * 1000
      : Math.min(30000, 2 ** attempt * 1000) * (0.5 + Math.random());
    await new Promise(r => setTimeout(r, waitMs));
  }
  throw new Error('rate limited: retries exhausted');
}

