type Decision = { allowed: boolean; remaining: number; retryAfterSec: number };

class TokenBucket {
  private tokens: number;
  private lastRefill: number; // ms

  constructor(
    private readonly capacity: number,    // burst B
    private readonly refillPerSec: number // steady rate R
  ) {
    this.tokens = capacity;
    this.lastRefill = Date.now();
  }

  private refill(now: number): void {
    const elapsedSec = (now - this.lastRefill) / 1000;
    if (elapsedSec <= 0) return;
    this.tokens = Math.min(this.capacity, this.tokens + elapsedSec * this.refillPerSec);
    this.lastRefill = now;
  }

  tryConsume(cost = 1, now = Date.now()): Decision {
    this.refill(now);
    if (this.tokens >= cost) {
      this.tokens -= cost;
      return { allowed: true, remaining: Math.floor(this.tokens), retryAfterSec: 0 };
    }
    const deficit = cost - this.tokens;
    const retryAfterSec = Math.ceil(deficit / this.refillPerSec);
    return { allowed: false, remaining: 0, retryAfterSec };
  }
}

// usage: 10 burst, 2/sec sustained
const bucket = new TokenBucket(10, 2);
console.log(bucket.tryConsume());       // allowed, remaining 9
